21	/**
22	 * Dialog for editing complex split configuration details.
23	 * Allows users to modify header index and column index for Excel file splitting.
24	 *
25	 * @author summer
26	 */
27	public class ConfigEditorView extends JDialog {
28	    private static final Logger log = LoggerFactory.getLogger(ConfigEditorView.class);
29	
30	    private String taskId;
31	    private JTable table;
32	    private ConfigView configView;
33	
34	    /**
35	     * Creates a new ConfigEditorView dialog.
36	     * 
37	     * @param panel the parent panel to determine the window ancestor
38	     * @param configView the parent config view to update after save
39	     * @param table the table containing the configuration data
40	     * @param row the row index in the table to edit
41	     * @param taskId the task ID for the configuration
42	     */
43	    public ConfigEditorView(JPanel panel, ConfigView configView, JTable table, int row, String taskId) {
44	        super(SwingUtilities.getWindowAncestor(panel));
45	        initComponents();
46	        this.taskId = taskId;
47	        this.table = table;
48	        this.configView = configView;
49	        fileNameText.setText(objToString(table.getValueAt(row, 0)));
50	        sheetNameText.setText(objToString(table.getValueAt(row, 1)));
51	        headerIndexText.setText(objToString(table.getValueAt(row, 2)));
52	        columnIndex.setText(objToString(table.getValueAt(row, 3)));
53	    }
54	
55	    /**
56	     * Handles the update button action.
57	     * Saves the modified configuration to database and refreshes the table view.
58	     */
59	    private void updateBtActionListener(ActionEvent e) {
60	        log.debug("Updating config for taskId: {}, file: {}", taskId, fileNameText.getText());
61	        try (SqlSession session = DatabaseInit.getSqlSession()) {
62	            ComplexSplitConfigMapper mapper = session.getMapper(ComplexSplitConfigMapper.class);
63	            ComplexSplitConfigEntity complexSplitConfigEntity = new ComplexSplitConfigEntity();
64	            complexSplitConfigEntity.setTaskId(taskId);
65	            complexSplitConfigEntity.setFieldName(fileNameText.getText());
66	            complexSplitConfigEntity.setSheetName(sheetNameText.getText());
67	            complexSplitConfigEntity.setHeaderIndex(Integer.parseInt(headerIndexText.getText()));
68	            complexSplitConfigEntity.setColumnIndex(Integer.parseInt(columnIndex.getText()));
69	            mapper.update(complexSplitConfigEntity);
70	            session.commit();
71	            log.info("Successfully updated config for taskId: {}", taskId);
72	            // update table
73	            List<ComplexSplitConfigEntity> complexSplitConfigEntities = mapper.selectAllByTaskId(taskId);
74	            List<Object[]> rowDatas = new ArrayList<>();
75	            for (ComplexSplitConfigEntity entity : complexSplitConfigEntities) {
76	                rowDatas.add(new Object[]{entity.getFieldName(), entity.getSheetName(), entity.getHeaderIndex(), entity.getColumnIndex()});
77	            }
78	            configView.setTableModel(rowDatas);
79	            this.setVisible(false);
80	        } catch (Exception ex) {
81	            log.error("Failed to update config for taskId: {}", taskId, ex);
82	        }
83	    }
