43	    /**
44	     * Sets the table model with configuration data
45	     * Columns: FileName, SheetName, HeaderIndex, SplitBYColumnIndex
46	     * Only columns with index > 4 are editable
47	     *
48	     * @param rowDatas List of row data arrays containing configuration values
49	     * @return This ConfigView instance for method chaining
50	     */
51	    public ConfigView setTableModel(List<Object[]> rowDatas) {
52	        String[] columns = {"FileName", "SheetName", "HeaderIndex", "SplitBYColumnIndex"};
53	        // Override isCellEditable to make columns beyond index 4 editable
54	        // First few columns (file info) remain non-editable for data integrity
55	        DefaultTableModel defaultTableModel = new DefaultTableModel(columns, 0) {
56	            @Override
57	            public boolean isCellEditable(int row, int column) {
58	                return column > 4;
59	            }
60	        };
61	        for (Object[] row : rowDatas) {
62	            defaultTableModel.addRow(row);
63	        }
64	        this.configInfo.setModel(defaultTableModel);
65	        return this;
66	    }
