77	    /**
78	     * Handles mouse click events on the configuration table.
79	     * Opens editor dialog when user double-clicks on a row.
80	     *
81	     * @param e MouseEvent containing click coordinates and information
82	     */
83	    private void configInfoMouseClicked(MouseEvent e) {
84	        // Check for double-click (>=2 to handle any multi-click scenario)
85	        if (e.getClickCount() >= 2) {
86	            // Convert click point to row index
87	            int row = configInfo.rowAtPoint(e.getPoint());
88	            if (row >= 0) {
89	                // Select the clicked row for visual feedback
90	                configInfo.setRowSelectionInterval(row, row);
91	                log.debug("Opening editor for row {}", row);
92	                // Open editor dialog for this row, passing table reference and row index
93	                new ConfigEditorView(contentPanel, this, configInfo, row, taskId).setVisible(true);
94	            }
95	        }
96	    }
