26	/**
27	 * Dialog window for managing email tags.
28	 * Allows users to view, add, and update email tags stored in the database.
29	 * Tags can be used to categorize email addresses in the address book.
30	 *
31	 * @author phoebej
32	 */
33	public class EmailTagsView extends JDialog {
34	    private static final Logger log = LoggerFactory.getLogger(EmailTagsView.class);
35	
36	    /** ID of the tag being updated (null for new tag creation) */
37	    private Long needUpdateId;
38	
39	    /**
40	     * Creates a new EmailTagsView dialog.
41	     *
42	     * @param panel the parent panel to determine the window ancestor
43	     */
44	    public EmailTagsView(JPanel panel) {
45	        super(SwingUtilities.getWindowAncestor(panel));
46	        ;
47	        initComponents();
48	    }
