50	    /**
51	     * Opens the tag view and loads all existing tags from database.
52	     * Displays tags in a table with ID and Tag columns.
53	     * Uses SwingWorker for background database query.
54	     */
55	    public void openTagView() {
56	        new SwingWorker<List<EmailTagEntity>, Void>() {
57	            @Override
58	            protected List<EmailTagEntity> doInBackground() throws Exception {
59	                log.debug("Loading email tags from database");
60	                try (SqlSession session = DatabaseInit.getSqlSession()) {
61	                    EmailTagMapper mapper = session.getMapper(EmailTagMapper.class);
62	                    return mapper.selectAll();
63	                }
64	            }
65	
66	            @Override
67	            protected void done() {
68	                List<EmailTagEntity> emailTagEntities = null;
69	                try {
70	                    emailTagEntities = get();
71	                    log.debug("Loaded {} email tags", emailTagEntities.size());
72	                    List<Object[]> rowData = new ArrayList<>();
73	                    for (EmailTagEntity emailTagEntity : emailTagEntities) {
74	                        rowData.add(new Object[]{emailTagEntity.getId(), emailTagEntity.getTag()});
75	                    }
76	                    if (!rowData.isEmpty()) {
77	                        String[] columns = {"ID", "Tag"};
78	                        DefaultTableModel model = new DefaultTableModel(columns, 0) {
79	                            @Override
80	                            public boolean isCellEditable(int row, int column) {
81	                                return column > 99;
82	                            }
83	                        };
84	                        for (Object[] row : rowData) {
85	                            model.addRow(row);
86	                        }
87	                        tagTable.setModel(model);
88	                    }
89	                    if (!EmailTagsView.this.isVisible()) {
90	                        EmailTagsView.this.setVisible(true); // Show only on first open
91	                    }
92	
93	                } catch (InterruptedException ex) {
94	                    log.error("Interrupted while loading email tags", ex);
95	                    throw new RuntimeException(ex);
96	                } catch (ExecutionException ex) {
97	                    log.error("Failed to load email tags", ex);
98	                    throw new RuntimeException(ex);
99	                }
100	
101	            }
102	        }.execute();
103	    }
104	
105	    /**
106	     * Handles add/update tag button action.
107	     * If button text is "AddNewTag", inserts a new tag to database.
108	     * If button text is "Update", updates the existing tag with needUpdateId.
109	     *
110	     * @param e the action event
111	     */
112	    private void addTagBtAction(ActionEvent e) {
113	        if (addTagBt.getText().equals("AddNewTag")) {
114	            new SwingWorker<Void, Void>() {
115	                private Exception error;
116	
117	                @Override
118	                protected Void doInBackground() throws Exception {
119	                    SwingUtilities.invokeLater(() -> {
120	                        progressBar1.setValue(0);
121	                        progressBar1.setStringPainted(true);
122	                        progressBar1.setString("Please wait...");
123	                        progressBar1.setVisible(true);
124	                    });
125	                    if (tagField.getText() != null && !tagField.getText().isEmpty()) {
126	                        log.debug("Inserting new tag: {}", tagField.getText());
127	                        try (SqlSession session = DatabaseInit.getSqlSession()) {
128	                            EmailTagMapper mapper = session.getMapper(EmailTagMapper.class);
129	                            EmailTagEntity emailTagEntity = new EmailTagEntity();
130	                            emailTagEntity.setTag(tagField.getText());
131	                            mapper.insert(emailTagEntity);
132	                            session.commit();
133	                            log.info("Successfully inserted tag: {}", tagField.getText());
134	                        } catch (Exception ex) {
135	                            error = ex;
136	                            log.error("Failed to insert tag: {}", tagField.getText(), ex);
137	                            throw ex;
138	                        }
139	                    } else {
140	                        throw new RuntimeException("Tag field is empty!");
141	                    }
142	
143	                    return null;
144	                }
145	
146	                @Override
147	                protected void done() {
148	                    try {
149	                        get();
150	                        progressBar1.setValue(100);
151	                        progressBar1.setString("Done");
152	                        openTagView();
153	                    } catch (Exception ex) {
154	                        progressBar1.setString("Error: " + ex.getMessage());
155	                        JOptionPane.showMessageDialog(EmailTagsView.this,
156	                                "Failed to add tag: " + ex.getMessage(),
157	                                "Error",
158	                                JOptionPane.ERROR_MESSAGE);
159	                    }
160	                }
161	            }.execute();
162	        } else if (addTagBt.getText().equals("Update")) {
163	            // Update Tags
164	            new SwingWorker<Void, Void>() {
165	                @Override
166	                protected Void doInBackground() throws Exception {
167	                    log.debug("Updating tag id={} with value: {}", needUpdateId, tagField.getText());
168	                    try (SqlSession session = DatabaseInit.getSqlSession()) {
169	                        EmailTagMapper mapper = session.getMapper(EmailTagMapper.class);
170	                        EmailTagEntity emailTagEntity = new EmailTagEntity();
171	                        emailTagEntity.setId(needUpdateId);
172	                        emailTagEntity.setTag(tagField.getText());
173	                        mapper.update(emailTagEntity);
174	                        session.commit();
175	                        log.info("Successfully updated tag id={}", needUpdateId);
176	                    }
177	                    return null;
178	                }
179	
180	                @Override
181	                protected void done() {
182	                    needUpdateId = null;
183	                    openTagView();
184	                    tagField.setText("");
185	                    addTagBt.setText("AddNewTag");
186	                }
187	            }.execute();
188	        }
189	    }
