212	     * @param e the mouse event
213	     */
214	    private void tagTableMouseClicked(MouseEvent e) {
215	        if (e.getClickCount() >= 2) {
216	            // Convert click point to row index
217	            int row = tagTable.rowAtPoint(e.getPoint());
218	            if (row >= 0) {
219	                // Select the clicked row for visual feedback
220	                tagTable.setRowSelectionInterval(row, row);
221	                // Open editor dialog for this row, passing table reference and row index
222	                Object value = tagTable.getValueAt(row, 0);
223	                if (value != null) {
224	                    needUpdateId = Long.parseLong(value.toString());
225	                }
226	                Object tag = tagTable.getValueAt(row, 1);
227	                if (needUpdateId != null && tag != null) {
228	                    addTagBt.setText("Update");
229	                    tagField.setText(tag.toString());
230	                    log.debug("Selected tag for update: id={}, tag={}", needUpdateId, tag);
231	                }
232	            }
233	        }
234	    }
