77	    public AddAddressView initTagsCompBox() {
78	        new SwingWorker<Void, Void>() {
79	            @Override
80	            protected Void doInBackground() throws Exception {
81	                comboBoxReady = false;
82	                try (SqlSession session = DatabaseInit.getSqlSession()) {
83	                    EmailTagMapper mapper = session.getMapper(EmailTagMapper.class);
84	                    List<EmailTagEntity> emailTagEntities = mapper.selectAll();
85	                    comboBox1.removeAllItems();
