100	    /**
101	     * Handles the save button action.
102	     * Validates the email address and saves/updates it to the database.
103	     *
104	     * @param e the action event
105	     */
106	    private void insertBtAction(ActionEvent e) {
107	        if (!StringUtil.checkEmail(addressField.getText())) {
108	            return;
109	        }
110	        boolean isEdit = editEntity != null;
111	        log.debug("{} email address: {}", isEdit ? "Updating" : "Inserting", addressField.getText());
112	        try (SqlSession session = DatabaseInit.getSqlSession()) {
113	            EmailAddressBookMapper mapper = session.getMapper(EmailAddressBookMapper.class);
114	            EmailAddressBookEntity emailAddressBookEntity = new EmailAddressBookEntity();
115	            if (isEdit) {
116	                emailAddressBookEntity.setId(editEntity.getId());
117	            }
118	            emailAddressBookEntity.setEmailAddress(addressField.getText());
119	            emailAddressBookEntity.setNickname(nicknameField.getText());
120	            emailAddressBookEntity.setTags(JSON.toJSONString(tags));
121	            if (isEdit) {
122	                mapper.update(emailAddressBookEntity);
123	                log.info("Successfully updated email address: {}", addressField.getText());
124	            } else {
125	                mapper.insert(emailAddressBookEntity);
126	                log.info("Successfully inserted email address: {}", addressField.getText());
127	            }
128	            session.commit();
129	            new QueryAllEmailInfoWorker(new QueryAllEmailInfoCallBack() {
130	                @Override
131	                public void onSuccess(List<EmailAddressBookEntity> emailAddressBookEntities) {
132	                    dataBaseInfo = emailAddressBookEntities;
133	                    log.debug("Loaded {} email addresses", emailAddressBookEntities.size());
134	                    if (dataBaseInfo != null && !dataBaseInfo.isEmpty()) {
135	                        List<Object[]> rowData = new ArrayList<>();
136	                        for (EmailAddressBookEntity info : dataBaseInfo) {
137	                            rowData.add(new Object[]{info.getId(), info.getEmailAddress(), info.getNickname(), info.getTags()});
138	                        }
139	                        emailAddressBookView.initTable(rowData, dataBaseInfo);
140	                    }
141	                }
142	
143	                @Override
144	                public void onFailure(Exception e) {
145	                    log.error("Failed to load email addresses", e);
146	                    JOptionPane.showMessageDialog(contentPanel,
147	                            "Can Not Find Any Email Address!",
148	                            "Warning",
149	                            JOptionPane.WARNING_MESSAGE);
150	                }
151	            }).execute();
152	            this.setVisible(false);
153	        } catch (Exception ex) {
154	            log.error("Failed to {} email address: {}", isEdit ? "update" : "insert", addressField.getText(), ex);
155	            this.setVisible(false);
156	            JOptionPane.showMessageDialog(this,
157	                    (isEdit ? "Can Not Update" : "Can Not Insert") + " Email Address :" + ex.getMessage(),
158	                    "Error",
159	                    JOptionPane.ERROR_MESSAGE);
160	        }
161	    }
