64	                    int row = addressInfoTable.rowAtPoint(e.getPoint());
65	                    if (row >= 0 && row < entities.size()) {
66	                        EmailAddressBookEntity entity = entities.get(row);
67	                        log.debug("Double-clicked row {}, opening edit view for: {}", row, entity.getEmailAddress());
68	                        new AddAddressView(pannel, EmailAddressBookView.this, entity).initTagsCompBox().setVisible(true);
