23	public class SideMenuBar extends JPanel implements LocaleChangeListener {
24	
25	    private static final int MENU_WIDTH = 160;
26	    private static final Color SELECTED_BG = new Color(0x2D, 0x2D, 0x2D);
27	    private static final Color SELECTED_TEXT = new Color(0xBB, 0x86, 0xFC);
28	    private static final Color HOVER_BG = new Color(0xE8, 0xE8, 0xE8);
29	    private static final Color DRAG_HIGHLIGHT = new Color(0xCC, 0xCC, 0xDD);
30	
31	    /**
32	     * Minimum pixel movement to be considered a drag (not a click)
33	     */
34	    private static final int DRAG_THRESHOLD = 8;
35	
36	    /**
37	     * Flat list of all pages in display order.
38	     * A null entry represents the separator between built-in and plugin sections.
39	     */
40	    private final List<Object> allPages;
41	    private final List<JLabel> menuItems;
42	    private final JPanel contentPanel;
43	    private int selectedIndex = -1;
44	
45	    private final JLabel titleLabel;
46	    private final JPanel menuContainer;
47	    private JPanel menuItemsPanel;
48	
49	    // ── Drag state ────────────────────────────────────────────────────────────
50	    private int draggedItemIndex = -1;
51	    private Point dragStartPoint = null;
52	    private boolean isDragging = false;
53	
54	    public SideMenuBar(SwissKitPageScaner.ScannedPages scannedPages, JPanel contentPanel) {
55	        this.contentPanel = contentPanel;
56	        this.menuItems = new ArrayList<>();
57	
58	        // Build flat list: builtin + separator + plugin
59	        this.allPages = new ArrayList<>();
60	        this.allPages.addAll(scannedPages.builtinPages());
61	        int builtinCount = scannedPages.builtinPages().size();
62	        if (!scannedPages.pluginPages().isEmpty()) {
63	            this.allPages.add(null); // separator marker
64	        }
65	        this.allPages.addAll(scannedPages.pluginPages());
66	
67	        setLayout(new BorderLayout());
68	        setPreferredSize(new Dimension(MENU_WIDTH, 0));
69	        setBackground(UIUtils.LIGHT_GRAY);
70	
71	        // Register for locale change notifications
