82	        titlePanel.setBackground(UIUtils.LIGHT_GRAY);
83	
84	        menuContainer = new JPanel(new BorderLayout());
85	        menuContainer.setBackground(UIUtils.LIGHT_GRAY);
86	
87	        rebuildMenu();
88	
