102	
103	    // ── Menu construction ─────────────────────────────────────────────────────
104	
105	    public void rebuildMenu() {
106	        menuContainer.removeAll();
107	        menuItems.clear();
108	
109	        menuItemsPanel = new JPanel();
110	        menuItemsPanel.setLayout(new BoxLayout(menuItemsPanel, BoxLayout.Y_AXIS));
111	        menuItemsPanel.setBackground(UIUtils.LIGHT_GRAY);
112	
113	        for (int i = 0; i < allPages.size(); i++) {
114	            Object page = allPages.get(i);
115	
116	            if (page == null) {
117	                // Separator between built-in and plugin sections
118	                JSeparator separator = new JSeparator(SwingConstants.HORIZONTAL);
119	                separator.setForeground(new Color(0xCC, 0xCC, 0xCC));
120	                separator.setMaximumSize(new Dimension(Integer.MAX_VALUE, 2));
121	                JPanel sepPanel = new JPanel(new BorderLayout());
122	                sepPanel.setBackground(UIUtils.LIGHT_GRAY);
123	                sepPanel.add(separator, BorderLayout.NORTH);
124	                sepPanel.setBorder(new EmptyBorder(4, 0, 4, 0));
125	                menuItemsPanel.add(sepPanel);
126	            } else {
127	                // Regular menu item
128	                JLabel item = createMenuItem(page, i);
129	                menuItems.add(item);
130	                menuItemsPanel.add(wrapWithDragSupport(item, i));
131	            }
132	        }
133	
134	        menuContainer.add(menuItemsPanel, BorderLayout.NORTH);
135	        menuContainer.revalidate();
136	        menuContainer.repaint();
137	    }
138	
139	    private JLabel createMenuItem(Object page, int flatIndex) {
140	        String menuName = SwissKitPageScaner.getMenuName(page);
141	        String iconPath = SwissKitPageScaner.getMenuIconPath(page);
142	        Icon menuIcon = iconPath != null && !iconPath.isEmpty() ? new ImageIcon(iconPath) : null;
143	        JLabel label = new JLabel(menuName, menuIcon, SwingConstants.CENTER);
144	        label.setFont(new Font("SansSerif", Font.PLAIN, 13));
145	        label.setForeground(UIUtils.TEXT_COLOR);
146	        label.setBackground(UIUtils.LIGHT_GRAY);
147	        label.setOpaque(true);
148	        label.setBorder(new EmptyBorder(12, 10, 12, 10));
149	        label.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
150	        label.setAlignmentX(Component.CENTER_ALIGNMENT);
151	        label.setHorizontalAlignment(SwingConstants.CENTER);
152	        label.putClientProperty("pageIndex", flatIndex);
153	
154	        String tip = SwissKitPageScaner.getMenuTooltip(page);
155	        if (tip != null) label.setToolTipText(tip);
156	
157	        return label;
158	    }
159	
160	    /**
161	     * Wrap a menu label in a full-width panel and attach all mouse logic.
162	     * Key fix: listeners go on BOTH the panel AND the label so events
163	     * are never swallowed by the child component.
164	     */
165	    private JPanel wrapWithDragSupport(JLabel label, int flatIndex) {
166	        JPanel panel = new JPanel(new GridBagLayout());
167	        panel.setBackground(UIUtils.LIGHT_GRAY);
168	        GridBagConstraints gbc = new GridBagConstraints();
169	        gbc.fill = GridBagConstraints.HORIZONTAL;
170	        gbc.weightx = 1.0;
171	        panel.add(label, gbc);
172	
173	        // Shared handler — attached to both panel and label
174	        MouseAdapter handler = new MouseAdapter() {
175	
176	            @Override
177	            public void mousePressed(MouseEvent e) {
178	                dragStartPoint = SwingUtilities.convertPoint(e.getComponent(), e.getPoint(), menuItemsPanel);
179	                draggedItemIndex = flatIndex;
180	                isDragging = false;
181	            }
182	
183	            @Override
184	            public void mouseReleased(MouseEvent e) {
185	                boolean wasDragging = isDragging;
186	                int dragFromIndex = draggedItemIndex;
187	                Point releasePoint = SwingUtilities.convertPoint(e.getComponent(), e.getPoint(), menuItemsPanel);
188	
189	                // Reset state before any UI change
190	                dragStartPoint = null;
191	                draggedItemIndex = -1;
192	                isDragging = false;
193	                clearDragHighlight();
194	
195	                if (wasDragging && dragFromIndex >= 0) {
196	                    int dropIndex = getDropIndex(releasePoint);
197	                    if (dropIndex != dragFromIndex && dropIndex != dragFromIndex + 1) {
198	                        reorderPages(dragFromIndex, dropIndex);
199	                    }
200	                } else {
201	                    // Plain click → navigate
202	                    selectPage(flatIndex);
203	                }
204	            }
205	
206	            @Override
207	            public void mouseEntered(MouseEvent e) {
208	                if (!isDragging && flatIndex != selectedIndex) {
209	                    label.setBackground(HOVER_BG);
210	                }
211	            }
212	
213	            @Override
214	            public void mouseExited(MouseEvent e) {
215	                if (!isDragging && flatIndex != selectedIndex) {
216	                    label.setBackground(UIUtils.LIGHT_GRAY);
217	                }
218	            }
219	
220	            @Override
221	            public void mouseDragged(MouseEvent e) {
222	                if (dragStartPoint == null) return;
223	
224	                Point current = SwingUtilities.convertPoint(e.getComponent(), e.getPoint(), menuItemsPanel);
225	                int dx = Math.abs(current.x - dragStartPoint.x);
226	                int dy = Math.abs(current.y - dragStartPoint.y);
227	
228	                if (!isDragging && (dx > DRAG_THRESHOLD || dy > DRAG_THRESHOLD)) {
229	                    isDragging = true;
230	                }
231	
232	                if (isDragging) {
233	                    updateDragHighlight(current, draggedItemIndex);
234	                }
235	            }
236	        };
237	
238	        panel.addMouseListener(handler);
239	        panel.addMouseMotionListener(handler);
240	        // Also attach to label so clicks/drags on the text are captured
241	        label.addMouseListener(handler);
242	        label.addMouseMotionListener(handler);
243	
244	        return panel;
245	    }
246	
247	    // ── Drag visuals ──────────────────────────────────────────────────────────
248	
249	    private void updateDragHighlight(Point mouseInPanel, int draggedIndex) {
250	        int dropIndex = getDropIndex(mouseInPanel);
251	
252	        for (int i = 0; i < menuItems.size(); i++) {
253	            JLabel lbl = menuItems.get(i);
254	            if (i == draggedIndex) {
255	                lbl.setBackground(DRAG_HIGHLIGHT);
256	            } else if (i == selectedIndex) {
257	                lbl.setBackground(SELECTED_BG);
258	            } else {
259	                lbl.setBackground(UIUtils.LIGHT_GRAY);
260	            }
261	        }
262	
263	        // Highlight insertion target
264	        if (dropIndex >= 0 && dropIndex < menuItems.size() && dropIndex != draggedIndex) {
265	            menuItems.get(dropIndex).setBackground(DRAG_HIGHLIGHT);
266	        }
267	    }
268	
269	    private void clearDragHighlight() {
270	        for (int i = 0; i < menuItems.size(); i++) {
271	            menuItems.get(i).setBackground(i == selectedIndex ? SELECTED_BG : UIUtils.LIGHT_GRAY);
272	        }
273	    }
274	
275	    // ── Drop index calculation ─────────────────────────────────────────────────
276	
277	    /**
278	     * Returns the index at which the dragged item should be inserted.
279	     * Compares mouse Y against the midpoint of each row.
280	     */
281	    private int getDropIndex(Point locationInPanel) {
282	        int count = menuItemsPanel.getComponentCount();
283	        if (count == 0) return 0;
284	
285	        int y = locationInPanel.y;
286	        int cumulative = 0;
287	
288	        for (int i = 0; i < count; i++) {
289	            Component comp = menuItemsPanel.getComponent(i);
290	            int h = comp.getHeight();
291	            // Insert before this row when cursor is in its upper half
292	            if (y < cumulative + h / 2) {
293	                return i;
294	            }
295	            cumulative += h;
296	        }
297	        return count; // insert at end
298	    }
299	
300	    // ── Reorder logic ─────────────────────────────────────────────────────────
301	
302	    private void reorderPages(int fromIndex, int toIndex) {
303	        // Clamp to valid insertion range
304	        toIndex = Math.max(0, Math.min(toIndex, allPages.size()));
305	
306	        // Remember which page was selected
307	        Object selectedPage = (selectedIndex >= 0 && selectedIndex < allPages.size())
308	                ? allPages.get(selectedIndex) : null;
309	
310	        Object moved = allPages.remove(fromIndex);
311	        // Adjust insertion index after removal
312	        int insertAt = (toIndex > fromIndex) ? toIndex - 1 : toIndex;
313	        insertAt = Math.max(0, Math.min(insertAt, allPages.size()));
314	        allPages.add(insertAt, moved);
315	
316	        SwissKitPageScaner.saveMenuOrder(allPages);
317	        rebuildMenu();
318	
319	        // Restore selection by page identity, not stale index
320	        if (selectedPage != null) {
321	            int newIdx = allPages.indexOf(selectedPage);
322	            if (newIdx >= 0) {
323	                selectedIndex = -1; // force refresh
324	                selectPage(newIdx);
325	                return;
326	            }
327	        }
328	        selectPage(0);
329	    }
330	
331	    // ── Public API ────────────────────────────────────────────────────────────
332	
333	    public void selectPage(int flatIndex) {
334	        if (flatIndex < 0 || flatIndex >= allPages.size()) return;
335	
336	        Object page = allPages.get(flatIndex);
337	        if (page == null) return; // separator, not selectable
338	
339	        // Calculate actual menu item index (menuItems excludes separators)
340	        int menuIdx = 0;
341	        for (int i = 0; i < flatIndex; i++) {
342	            if (allPages.get(i) != null) {
343	                menuIdx++;
344	            }
345	        }
346	
347	        // Deselect previous
348	        if (selectedIndex >= 0 && selectedIndex < menuItems.size()) {
349	            menuItems.get(selectedIndex).setBackground(UIUtils.LIGHT_GRAY);
350	            menuItems.get(selectedIndex).setForeground(UIUtils.TEXT_COLOR);
351	        }
352	
353	        selectedIndex = menuIdx;
354	        menuItems.get(menuIdx).setBackground(SELECTED_BG);
355	        menuItems.get(menuIdx).setForeground(SELECTED_TEXT);
356	
357	        if (contentPanel != null) {
358	            contentPanel.removeAll();
359	            contentPanel.add(SwissKitPageScaner.getPanel(page), BorderLayout.CENTER);
360	            contentPanel.revalidate();
361	            contentPanel.repaint();
362	        }
363	    }
364	
365	    public int getSelectedIndex() {
366	        return selectedIndex;
367	    }
368	
369	    public void setTitle(String title) {
370	        titleLabel.setText(title);
371	    }
372	
373	    public void setPages(SwissKitPageScaner.ScannedPages scannedPages) {
374	        this.allPages.clear();
375	        this.allPages.addAll(scannedPages.builtinPages());
376	        int builtinCount = scannedPages.builtinPages().size();
377	        if (!scannedPages.pluginPages().isEmpty()) {
378	            this.allPages.add(null);
379	        }
380	        this.allPages.addAll(scannedPages.pluginPages());
381	        rebuildMenu();
382	    }
383	
384	    @Override
385	    public void onLocaleChanged(Language newLanguage) {
386	        titleLabel.setText(I18nManager.get("app.name"));
387	        rebuildMenu();
388	    }
389	}
