13	import org.slf4j.LoggerFactory;
14	
15	import javax.swing.*;
16	import javax.swing.border.EmptyBorder;
17	import java.awt.*;
18	import java.net.URL;
19	import java.util.ArrayList;
20	import java.util.List;
21	import java.util.stream.Collectors;
22	
23	/**
24	 * Home page class that serves as the main application container.
25	 * Manages the application window, side menu bar, and automatic page discovery.
26	 *
27	 * @author phoebej
28	 * @version 1.00
29	 * @date 2026/3/1
30	 */
31	public class HomePage implements LocaleChangeListener {
32	
33	    private static final Logger logger = LoggerFactory.getLogger(HomePage.class);
34	
35	    private static HomePage instance;
36	
37	    private SideMenuBar sideMenuBar;
38	    private SwissKitPageScaner.ScannedPages scannedPages;
39	
40	    /**
41	     * Initializes and displays the main application window.
42	     * Sets up the FlatLaf theme, discovers all KitPage plugins, creates the side menu,
43	     * and displays the first registered page by default.
44	     * Should be called once from the EDT after DatabaseInit completes successfully.
45	     */
46	    public void init() {
47	        // Register for locale change notifications
48	        I18nManager.addListener(this);
49	
50	        FlatIntelliJLaf.setup();
51	
52	        UIManager.put("ProgressBar.arc", 10);
53	        UIManager.put("ProgressBar.foreground", new Color(64, 158, 255));
54	        UIManager.put("ProgressBar.background", new Color(240, 240, 240));
55	        UIManager.put("ProgressBar.selectionForeground", Color.WHITE);
56	        UIManager.put("ProgressBar.selectionBackground", Color.GRAY);
57	
58	        JFrame frame = new JFrame(AppInfo.getFullName());
59	        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
60	        frame.setLocationRelativeTo(null);
61	
62	        // Set application icon
63	        setAppIcon(frame);
64	
65	        // Initialize pages using KitPageScanner
66	        scannedPages = SwissKitPageScaner.scan();
67	
68	        // Content panel
69	        JPanel contentPanel = new JPanel(new BorderLayout());
70	        contentPanel.setBorder(new EmptyBorder(20, 20, 20, 20));
71	        contentPanel.setBackground(Color.WHITE);
72	
73	        // Side menu bar
74	        sideMenuBar = new SideMenuBar(scannedPages, contentPanel);
75	
76	        // Set singleton instance for hot-deploy coordination
77	        instance = this;
78	
79	        // Main panel
80	        JPanel mainPanel = new JPanel(new BorderLayout());
81	        mainPanel.add(sideMenuBar, BorderLayout.WEST);
82	        mainPanel.add(contentPanel, BorderLayout.CENTER);
83	
84	        frame.add(mainPanel);
85	
86	        // Select the first page by default
87	        sideMenuBar.selectPage(0);
88	
89	        frame.setSize(new Dimension(900, 600));
90	        frame.setMinimumSize(new Dimension(800, 500));
91	        frame.setLocationRelativeTo(null);
92	        frame.setVisible(true);
93	
94	        logger.info("Application started with {} pages", scannedPages.totalCount());
95	    }
96	
97	    /**
98	     * Set application icon
99	     * Place icon file in resources directory, supports: icon.png, icon.jpg, app.png
100	     */
101	    private void setAppIcon(JFrame frame) {
102	        String[] iconPaths = {"/icon.png", "/icon.jpg", "/app.png"};
103	
104	        for (String path : iconPaths) {
105	            URL url = getClass().getResource(path);
106	            if (url != null) {
107	                frame.setIconImage(new ImageIcon(url).getImage());
108	                return;
109	            }
110	        }
111	        // Use default when icon file not found
112	        logger.info("Application icon not found. Please add icon.png to resources directory");
113	    }
114	
115	    /**
116	     * Returns the singleton HomePage instance.
117	     *
118	     * @return the HomePage instance, or null if not yet initialized
119	     */
120	    public static HomePage getInstance() {
121	        return instance;
122	    }
123	
124	    /**
125	     * Refreshes the sidebar menu after plugin hot-deploy/reload/uninstall.
126	     *
127	     * @param newPluginPages KitPages from deployed/reloaded plugin (pass null for uninstall)
128	     */
129	    public void refreshSidebar(List<Object> newPluginPages) {
130	        if (sideMenuBar == null) {
131	            return;
132	        }
133	
134	        if (newPluginPages != null && !newPluginPages.isEmpty()) {
135	            // Deploy/reload: merge new plugin pages into current plugin list
136	            List<Object> currentPlugins = new ArrayList<>(scannedPages.pluginPages());
137	            List<String> newClassNames = newPluginPages.stream()
138	                    .map(p -> p.getClass().getName())
139	                    .collect(Collectors.toList());
140	
141	            currentPlugins.removeIf(p -> newClassNames.contains(p.getClass().getName()));
142	            currentPlugins.addAll(newPluginPages);
143	
144	            // Filter disabled
145	            currentPlugins.removeIf(p -> !PluginLoader.isPageEnabled(p));
146	
147	            // Rebuild ScannedPages with merged plugins
148	            SwissKitPageScaner.ScannedPages merged = new SwissKitPageScaner.ScannedPages(
149	                    scannedPages.builtinPages(), currentPlugins);
150	            SwissKitPageScaner.applySavedOrder(merged);
151	            scannedPages = merged;
152	        } else {
153	            // Uninstall or refresh: re-scan everything
154	            scannedPages = SwissKitPageScaner.scan();
155	        }
156	
157	        sideMenuBar.setPages(scannedPages);
158	    }
159	
160	    /**
161	     * @deprecated Use {@link #refreshSidebar(List)} instead.
162	     */
163	    @Deprecated
164	    public void refreshSidebar() {
165	        refreshSidebar(null);
166	    }
167	
168	    @Override
169	    public void onLocaleChanged(Language newLanguage) {
170	        if (sideMenuBar != null) {
171	            SwingUtilities.invokeLater(() -> sideMenuBar.rebuildMenu());
172	        }
173	    }
174	}
