54	     *
55	     * @return true if validation passes, false otherwise
56	     */
57	    private boolean validateForm() {
58	        // Validate To tag is required
59	        if (toTagcomboBox.getSelectedItem() == null || toTagcomboBox.getSelectedItem().toString().trim().isEmpty()) {
60	            JOptionPane.showMessageDialog(this, "Please select a To tag", "Validation Error", JOptionPane.ERROR_MESSAGE);
61	            return false;
62	        }
63	
64	        // Validate attachment folder is selected when checkbox is enabled
65	        if (attachmentByTagCheckBox.isSelected()) {
66	            String attPath = attPathField.getText();
67	            if (attPath == null || attPath.trim().isEmpty()) {
68	                JOptionPane.showMessageDialog(this, "Please select an attachment folder", "Validation Error", JOptionPane.ERROR_MESSAGE);
69	                return false;
70	            }
71	        }
72	
73	        return true;
