76	    /**
77	     * Save button action event. Saves configuration to database in background.
78	     */
79	    private void saveBtAction(ActionEvent e) {
80	        if (!validateForm()) {
81	            return;
82	        }
83	
84	        new SwingWorker<Void, Void>() {
85	            @Override
86	            protected Void doInBackground() throws Exception {
87	                try (SqlSession session = DatabaseInit.getSqlSession()) {
88	                    EmailMassSentConfigMapper mapper = session.getMapper(EmailMassSentConfigMapper.class);
89	
90	                    // Build config entity
91	                    EmailMassSentConfigEntity config = new EmailMassSentConfigEntity();
92	                    config.setTaskId(taskId);
93	                    TagComBoxItemDto toSelectedItem = (TagComBoxItemDto) toTagcomboBox.getSelectedItem();
94	                    if (toSelectedItem != null) {
95	                        config.setToTag(toSelectedItem.getId().toString());
96	                    }
97	                    if (ccTagComboBox.getSelectedItem() != null) {
98	                        TagComBoxItemDto selectedItem = (TagComBoxItemDto) ccTagComboBox.getSelectedItem();
99	                        config.setCcTag(selectedItem.getId().toString());
100	                    } else {
101	                        config.setCcTag(null);
102	                    }
103	                    config.setSentAtt(attachmentByTagCheckBox.isSelected());
104	                    config.setAttFolderPath(attachmentByTagCheckBox.isSelected() ? attPathField.getText() : null);
105	
106	                    // Insert or update config
107	                    mapper.upsert(config);
108	                    session.commit();
109	                    log.info("Mass sent config saved for taskId: {}", taskId);
110	                }
111	
112	                return null;
113	            }
114	
115	            @Override
116	            protected void done() {
117	                JOptionPane.showMessageDialog(MassSentConfigView.this, "Configuration saved successfully", "Success", JOptionPane.INFORMATION_MESSAGE);
118	                dispose();
119	            }
120	        }.execute();
121	    }
