158	     */
159	    private void loadTags() {
160	        try (SqlSession session = DatabaseInit.getSqlSession()) {
161	            EmailTagMapper tagMapper = session.getMapper(EmailTagMapper.class);
162	            List<EmailTagEntity> tags = tagMapper.selectAll();
163	
164	            toTagcomboBox.removeAllItems();
165	            ccTagComboBox.removeAllItems();
166	
167	            for (EmailTagEntity tag : tags) {
168	                TagComBoxItemDto tagComBoxItemDto = new TagComBoxItemDto(tag.getId(), tag.getTag());
169	                toTagcomboBox.addItem(tagComBoxItemDto);
170	                ccTagComboBox.addItem(tagComBoxItemDto);
171	            }
172	            toTagcomboBox.setSelectedIndex(-1);
173	            ccTagComboBox.setSelectedIndex(-1);
174	        } catch (Exception ex) {
175	            log.error("Failed to load tags", ex);
176	            JOptionPane.showMessageDialog(this, "Failed to load tags: " + ex.getMessage(), "Error", JOptionPane.ERROR_MESSAGE);
177	        }
178	    }
