186	            EmailMassSentConfigEntity config = mapper.selectByTaskId(taskId);
187	
188	            if (config != null) {
189	                toTagcomboBox.setSelectedItem(config.getToTag());
190	                ccTagComboBox.setSelectedItem(config.getCcTag());
191	                attachmentByTagCheckBox.setSelected(config.isSentAtt());
192	                attPathField.setText(config.getAttFolderPath() != null ? config.getAttFolderPath() : "");
193	            }
194	        } catch (Exception ex) {
195	            log.error("Failed to load config for taskId: {}", taskId, ex);
196	        }
197	    }
