180	    /**
181	     * Handle the mutual exclusion logic between splitBySheetCheckBox and splitByColumnCheckBox
182	     * When one checkbox is selected, the other is disabled and unselected
183	     */
184	    private void checkBoxInterlocked() {
185	        if (splitBySheetCheckBox.isSelected()) {
186	            splitByColumnCheckBox.setSelected(false);
187	            splitByColumnCheckBox.setEnabled(false);
188	        } else {
189	            splitByColumnCheckBox.setEnabled(true);
190	        }
191	        if (splitByColumnCheckBox.isSelected()) {
192	            splitBySheetCheckBox.setEnabled(false);
193	            splitBySheetCheckBox.setSelected(false);
194	        } else {
195	            splitBySheetCheckBox.setEnabled(true);
196	        }
197	    }
