120	    /**
121	     * Queries and displays the saved mass send configuration for the current task.
122	     * Shows To/Cc tags, attachment settings, and folder path in a dialog.
123	     *
124	     * @param e the action event triggered by viewSentConfigBt
125	     */
126	    private void viewSentConfigBtAction(ActionEvent e) {
127	        if (taskId == null) {
128	            return;
129	        }
130	
131	        new SwingWorker<Void, Void>() {
132	            private EmailMassSentConfigEntity config;
133	            private List<EmailTagEntity> tagList;
134	
135	            @Override
136	            protected Void doInBackground() throws Exception {
137	                try (SqlSession session = DatabaseInit.getSqlSession()) {
138	                    EmailMassSentConfigMapper mapper = session.getMapper(EmailMassSentConfigMapper.class);
139	                    EmailTagMapper tagMapper = session.getMapper(EmailTagMapper.class);
140	                    tagList = tagMapper.selectAll();
141	                    config = mapper.selectByTaskId(taskId);
142	                }
143	                return null;
144	            }
145	
146	            @Override
147	            protected void done() {
148	                try {
149	                    StringBuilder message = new StringBuilder();
150	                    String toTagName = null;
151	                    String ccTagName = null;
152	                    if (config != null && tagList != null) {
153	                    for (EmailTagEntity tag : tagList) {
154	                        if (config.getToTag() != null && tag.getId().toString().equals(config.getToTag())) {
155	                            toTagName = tag.getTag();
156	                        }
157	                        if (config.getCcTag() != null && tag.getId().toString().equals(config.getCcTag())) {
158	                            ccTagName = tag.getTag();
159	                        }
160	                    }
161	                    }
162	                    message.append("<html><body>");
163	                    message.append("<p><b>Task ID:</b> ").append(taskId).append("</p>");
164	                    message.append("<p><b>To Tag:</b> ").append(toTagName).append("</p>");
165	                    message.append("<p><b>Cc Tag:</b> ").append(ccTagName).append("</p>");
166	                    message.append("<p><b>Send Attachment:</b> ").append(config != null && config.isSentAtt() ? "Yes" : "No").append("</p>");
167	                    message.append("<p><b>Attachment Folder:</b> ").append(config != null && config.getAttFolderPath() != null ? config.getAttFolderPath() : "N/A").append("</p>");
168	                    message.append("</body></html>");
169	
170	                    if (config == null) {
171	                        JOptionPane.showMessageDialog(emailPanel, "No configuration found for this task", "Info", JOptionPane.INFORMATION_MESSAGE);
172	                    } else {
173	                        JOptionPane.showMessageDialog(emailPanel, message.toString(), "Mass Sent Configuration", JOptionPane.INFORMATION_MESSAGE);
174	                    }
175	                } catch (Exception ex) {
176	                    log.error("Failed to load config for taskId: {}", taskId, ex);
177	                    JOptionPane.showMessageDialog(emailPanel, "Failed to load config: " + ex.getMessage(), "Error", JOptionPane.ERROR_MESSAGE);
178	                }
179	            }
180	        }.execute();
181	    }
