193	    /**
194	     * Handles the view sent log button action.
195	     * Loads all email sent logs from database and displays them in a dialog.
196	     */
197	    private void viewSentLogBtAction(ActionEvent e) {
198	        log.debug("View sent log button clicked");
199	        new SwingWorker<List<EmailSentLogEntity>, Void>() {
200	            @Override
201	            protected List<EmailSentLogEntity> doInBackground() throws Exception {
202	                log.debug("Loading email sent logs from database");
203	                try (SqlSession session = DatabaseInit.getSqlSession()) {
204	                    EmailSentLogMapper mapper = session.getMapper(EmailSentLogMapper.class);
205	                    return mapper.selectAll();
206	                }
207	            }
208	
209	            @Override
210	            protected void done() {
211	                try {
212	                    List<EmailSentLogEntity> logs = get();
213	                    if (logs == null || logs.isEmpty()) {
214	                        log.info("No email sent logs found");
215	                        JOptionPane.showMessageDialog(emailPanel,
216	                                "Empty Email Sent Log",
217	                                "Info",
218	                                JOptionPane.INFORMATION_MESSAGE);
219	                    } else {
220	                        log.info("Loaded {} email sent logs", logs.size());
221	                        List<Object[]> rowData = new ArrayList<>();
222	                        for (EmailSentLogEntity logEntry : logs) {
223	                            rowData.add(new Object[]{logEntry.getId(), logEntry.getSubject(), logEntry.getTo(), logEntry.getCc(), logEntry.getBcc(), logEntry.getContent(), logEntry.getAttachment(), logEntry.getSendTime(), logEntry.isSuccess()});
224	                        }
225	                        new ViewEmailSentLogView(emailPanel).updateTable(rowData).setVisible(true);
226	                    }
227	                } catch (Exception ex) {
228	                    log.error("Failed to load email sent logs", ex);
229	                    JOptionPane.showMessageDialog(emailPanel,
230	                            "Error:" + ex.getMessage(),
231	                            "Warning",
232	                            JOptionPane.WARNING_MESSAGE);
233	                }
234	            }
235	        }.execute();
236	    }
