503	    /**
504	     * Extracts HTML content from the editor for email sending.
505	     * Uses HTMLEditorKit to properly get the HTML content including multi-line text and formatting.
506	     * Removes the outer html and body tags to get just the body content.
507	     *
508	     * @return HTML string suitable for email body
509	     */
510	    private String getEditorHtmlContent() {
511	        String html;
512	        try {
513	            HTMLEditorKit kit = (HTMLEditorKit) body.getEditorKit();
514	            StringWriter writer = new StringWriter();
515	            kit.write(writer, body.getDocument(), 0, body.getDocument().getLength());
516	            html = writer.toString();
517	        } catch (Exception e) {
518	            log.error("Failed to get HTML content from editor, falling back to getText()", e);
519	            html = body.getText();
520	        }
521	        if (html.startsWith("<html>")) {
522	            int bodyStart = html.toLowerCase().indexOf("<body");
523	            if (bodyStart != -1) {
524	                bodyStart = html.indexOf(">", bodyStart) + 1;
525	                int bodyEnd = html.toLowerCase().indexOf("</body>");
526	                if (bodyEnd != -1) {
527	                    html = html.substring(bodyStart, bodyEnd).trim();
528	                }
529	            }
530	        }
531	        return html;
532	    }
