282	    private void deployPluginBtAction(ActionEvent e) {
283	        String path = pluginPath.getText();
284	        if (path == null || path.isEmpty()) {
285	            JOptionPane.showMessageDialog(settingTable,
286	                    "Please select a plugin JAR first",
287	                    "No Selection", JOptionPane.WARNING_MESSAGE);
288	            return;
289	        }
290	
291	        File source = new File(path);
292	        try {
293	            File canonical = source.getCanonicalFile();
294	            if (!canonical.exists() || !canonical.getName().toLowerCase().endsWith(".jar")) {
295	                JOptionPane.showMessageDialog(settingTable,
296	                        "Invalid JAR file selected",
297	                        "Invalid File", JOptionPane.ERROR_MESSAGE);
298	                return;
299	            }
300	            // Prevent path traversal attacks
301	            if (!canonical.getParentFile().equals(source.getParentFile())) {
302	                JOptionPane.showMessageDialog(settingTable,
303	                        "Invalid JAR file path: path traversal not allowed",
304	                        "Invalid File", JOptionPane.ERROR_MESSAGE);
305	                return;
306	            }
307	        } catch (java.io.IOException ex) {
308	            JOptionPane.showMessageDialog(settingTable,
309	                    "Invalid JAR file path",
310	                    "Invalid File", JOptionPane.ERROR_MESSAGE);
