315	            @Override
316	            protected List<Object> doInBackground() throws Exception {
317	                File pluginDir = Path.of(PluginLoader.PLUGIN_DIR).toFile();
318	                pluginDir.mkdirs();
319	
320	                Path target = pluginDir.toPath().resolve(source.getName());
321	                log.debug("Copying plugin from {} to {}", source, target);
322	                Files.copy(source.toPath(), target, StandardCopyOption.REPLACE_EXISTING);
323	                log.info("Copied plugin to: {}", target);
324	
325	                return PluginLoader.deployPlugin(target.toFile());
326	            }
