413	    /**
414	     * Handles the plugin uninstall action.
415	     * Deletes the selected plugin JAR file from the plugins directory.
416	     *
417	     * @param e the action event
418	     */
419	    private void uninstallPluginBtAction(ActionEvent e) {
420	        int selectedRow = installedPluginTable.getSelectedRow();
421	        if (selectedRow < 0) {
422	            JOptionPane.showMessageDialog(settingTable,
423	                    "Please select a plugin to uninstall",
424	                    "No Selection",
425	                    JOptionPane.WARNING_MESSAGE);
426	            return;
427	        }
428	
429	        String pluginName = (String) installedPluginTable.getValueAt(selectedRow, 0);
430	        int confirm = JOptionPane.showConfirmDialog(settingTable,
431	                "Uninstall plugin: " + pluginName + "?",
432	                "Confirm Uninstall", JOptionPane.YES_NO_OPTION);
433	
434	        if (confirm == JOptionPane.YES_OPTION) {
435	            // Disable button during uninstall
436	            uninstallPluginBt.setEnabled(false);
437	
438	            // Use SwingWorker to handle background deletion with GC
439	            new SwingWorker<Boolean, Void>() {
440	                @Override
441	                protected Boolean doInBackground() {
442	                    // Step 1: Refresh sidebar to remove plugin page references
443	                    SwingUtilities.invokeLater(() -> HomePage.getInstance().refreshSidebar());
444	                    SwingUtilities.invokeLater(() -> refreshPluginList());
445	
446	                    // Step 2: Close the ClassLoader and trigger GC
447	                    PluginLoader.unloadPlugin(pluginName);
448	                    PluginManager.unregisterPlugin(pluginName);
449	
450	                    // Step 3: Retry deletion with GC between attempts
451	                    File pluginFile = new File(PluginLoader.PLUGIN_DIR, pluginName);
452	                    log.info("Attempting to delete plugin file: {}", pluginFile.getAbsolutePath());
453	                    log.info("File exists before delete: {}", pluginFile.exists());
454	
455	                    for (int i = 0; i < 5; i++) {
456	                        boolean deleteResult = pluginFile.delete();
457	                        boolean existsAfter = pluginFile.exists();
458	                        log.info("Delete attempt {}: delete()={}, exists()={}", i + 1, deleteResult, existsAfter);
459	
460	                        if (deleteResult && !existsAfter) {
461	                            log.info("Plugin file deleted successfully on attempt {}", i + 1);
462	                            return true;
463	                        }
464	
465	                        // Wait and suggest GC for Windows file handle release
466	                        try {
467	                            Thread.sleep(1000);
468	                        } catch (InterruptedException ignored) {
469	                        }
470	                        System.gc();
471	                    }
472	
473	                    // Final check: verify file is actually deleted
474	                    boolean finalExists = pluginFile.exists();
475	                    log.info("Final exists check: {}", finalExists);
476	                    return !finalExists;
477	                }
478	
479	                @Override
480	                protected void done() {
481	                    uninstallPluginBt.setEnabled(true);
482	                    boolean deleted;
483	                    try {
484	                        deleted = get();
485	                    } catch (Exception e) {
486	                        deleted = false;
487	                    }
488	                    SwingUtilities.invokeLater(() -> {
489	                        HomePage.getInstance().refreshSidebar();
490	                        refreshPluginList();
491	                    });
492	
493	                    if (deleted) {
494	                        JOptionPane.showMessageDialog(settingTable,
495	                                "Plugin uninstalled successfully.",
496	                                "Uninstall Success",
497	                                JOptionPane.INFORMATION_MESSAGE);
498	                    } else {
499	                        JOptionPane.showMessageDialog(settingTable,
500	                                "Failed to delete plugin file. Please restart the application and try again.",
501	                                "Error",
502	                                JOptionPane.ERROR_MESSAGE);
503	                    }
504	                }
505	            }.execute();
506	        }
507	    }
