509	    /**
510	     * Refreshes the installed plugins table with current plugin directory contents.
511	     */
512	    private void refreshPluginList() {
513	        List<File> plugins = PluginLoader.getInstalledPlugins();
514	        List<Object[]> rowData = new ArrayList<>();
515	        for (File plugin : plugins) {
516	            String size;
517	            long bytes = plugin.length();
518	            if (bytes < 1024) {
519	                size = bytes + " B";
520	            } else if (bytes < 1024 * 1024) {
521	                size = String.format("%.1f KB", bytes / 1024.0);
522	            } else {
523	                size = String.format("%.1f MB", bytes / (1024.0 * 1024.0));
524	            }
525	
526	            PluginLoader.PluginState state = PluginLoader.getPluginState(plugin.getName());
527	            String version = state != null && state.getPluginVersion() != null ? state.getPluginVersion() : "N/A";
528	            boolean isEnabled = state == null || state.isEnabled();
529	            String status = isEnabled ? "Enabled" : "Disabled";
530	
531	            rowData.add(new Object[]{plugin.getName(), version, status, size});
532	        }
533	        String[] columns = {"Plugin Name", "Version", "Status", "Size"};
534	        TableUtil.initTable(installedPluginTable, columns, rowData, 2);
535	    }
