645	    /**
646	     * Validates and saves the email server settings to the database.
647	     * Reads SMTP address, port, email address, and password from the form fields.
648	     *
649	     * @param e the action event triggered by saveBtAction
650	     */
651	    private void saveBtAction(ActionEvent e) {
652	        // Validate required fields before saving
653	        String smtpAddress = textField1.getText().trim();
654	        String smtpPortStr = textField2.getText().trim();
655	        String email = textField3.getText().trim();
656	        String password = textField4.getText().trim();
657	        String fromAddress = textField5.getText().trim();
658	
659	        // Check if required fields are empty
660	        if (smtpAddress.isEmpty()) {
661	            JOptionPane.showMessageDialog(settingTable,
662	                    "ServerUrl cannot be empty!",
663	                    "Validation Error",
664	                    JOptionPane.ERROR_MESSAGE);
665	            textField1.requestFocusInWindow();
666	            return;
667	        }
668	
669	        if (smtpPortStr.isEmpty()) {
670	            JOptionPane.showMessageDialog(settingTable,
671	                    "ServerPort cannot be empty!",
672	                    "Validation Error",
673	                    JOptionPane.ERROR_MESSAGE);
674	            textField2.requestFocusInWindow();
675	            return;
676	        }
677	
678	        // Validate port is a valid number
679	        int smtpPort;
680	        try {
681	            smtpPort = Integer.parseInt(smtpPortStr);
682	            if (smtpPort <= 0 || smtpPort > 65535) {
683	                JOptionPane.showMessageDialog(settingTable,
684	                        "ServerPort must be a valid port number (1-65535)!",
685	                        "Validation Error",
686	                        JOptionPane.ERROR_MESSAGE);
687	                textField2.requestFocusInWindow();
688	                return;
689	            }
690	        } catch (NumberFormatException ex) {
691	            JOptionPane.showMessageDialog(settingTable,
692	                    "ServerPort must be a valid number!",
693	                    "Validation Error",
694	                    JOptionPane.ERROR_MESSAGE);
695	            textField2.requestFocusInWindow();
696	            return;
697	        }
698	
699	        if (email.isEmpty()) {
700	            JOptionPane.showMessageDialog(settingTable,
701	                    "UserName cannot be empty!",
702	                    "Validation Error",
703	                    JOptionPane.ERROR_MESSAGE);
704	            textField3.requestFocusInWindow();
705	            return;
706	        }
707	
708	        if (password.isEmpty()) {
709	            JOptionPane.showMessageDialog(settingTable,
710	                    "PassWord cannot be empty!",
711	                    "Validation Error",
712	                    JOptionPane.ERROR_MESSAGE);
713	            textField4.requestFocusInWindow();
714	            return;
715	        }
716	
717	        if (fromAddress.isEmpty()) {
718	            JOptionPane.showMessageDialog(settingTable,
719	                    "FromAddress cannot be empty!",
720	                    "Validation Error",
721	                    JOptionPane.ERROR_MESSAGE);
722	            textField5.requestFocusInWindow();
723	            return;
724	        }
725	
726	        // Validate TLS and SSL are not both selected
727	        if (isTsl.isSelected() && isSsl.isSelected()) {
728	            JOptionPane.showMessageDialog(settingTable,
729	                    "TSL and SSL cannot be both selected!",
730	                    "Validation Error",
731	                    JOptionPane.ERROR_MESSAGE);
732	            return;
733	        }
734	
735	        // All validations passed, proceed with database save
736	        log.debug("Starting to save email settings");
737	        new SwingWorker<Void, Void>() {
738	            @Override
739	            protected Void doInBackground() throws Exception {
740	                try (SqlSession session = DatabaseInit.getSqlSession()) {
741	                    SwissKitSettingEmailMapper mapper = session.getMapper(SwissKitSettingEmailMapper.class);
742	
743	                    // Delete all existing records first to keep only latest data
744	                    log.debug("Deleting existing email settings from database");
745	                    mapper.deleteAll();
746	
747	                    // Create entity with validated values
748	                    SwissKitSettingEmailEntity entity = new SwissKitSettingEmailEntity();
749	                    entity.setEmail(email);
750	                    entity.setPassword(password);
751	                    entity.setSmtpAddress(smtpAddress);
752	                    entity.setSmtpPort(smtpPort);
753	                    entity.setNeedTLS(isTsl.isSelected());
754	                    entity.setNeedSSL(isSsl.isSelected());
755	                    entity.setFromAddress(fromAddress);
756	
757	                    // Insert new record
758	                    log.debug("Inserting new email settings: smtpAddress={}, smtpPort={}, email={}, fromAddress={}, needTLS={}, needSSL={}",
759	                            smtpAddress, smtpPort, email, fromAddress, isTsl.isSelected(), isSsl.isSelected());
760	                    mapper.insert(entity);
761	                    session.commit();
762	
763	                    log.info("Email settings saved successfully: smtpAddress={}, smtpPort={}, email={}",
764	                            smtpAddress, smtpPort, email);
765	                } catch (Exception e) {
766	                    log.error("Failed to save email settings to database", e);
767	                    throw e;
768	                }
769	                return null;
770	            }
771	
772	            @Override
773	            protected void done() {
774	                try {
775	                    get();
776	                    JOptionPane.showMessageDialog(settingTable,
777	                            "Email settings saved successfully!",
778	                            "Success",
779	                            JOptionPane.INFORMATION_MESSAGE);
780	                } catch (Exception e) {
781	                    log.error("Error in save completion", e);
782	                    JOptionPane.showMessageDialog(settingTable,
783	                            "Failed to save email settings: " + e.getMessage(),
784	                            "Error",
785	                            JOptionPane.ERROR_MESSAGE);
786	                }
787	            }
788	        }.execute();
789	
790	    }
