                        AppSettingEntity entity = new AppSettingEntity();
                        entity.setSettingKey("language");
                        entity.setSettingValue(language.getCode());
                        mapper.insert(entity);
                    }
                    session.commit();
                }
                return null;
            }
        }.execute();
    }

